VALUES
  ('public-health-specialist-moex-00417', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某公司欲執行本年度職場健康促進介入方案的成效評價，下列對各項評價指標之敘述，何者 正確？', '["「了解計畫中的資源運用是否理想」是屬於「過程評價」指標", "「參加介入方案的員工是否更能自我壓力管理」是屬於「結果評價」指標", "「了解員工的行為是否受到介入方案影響而改變」是屬於「過程評價」指標", "「了解介入方案是否依照規劃的進度推動」是屬於「影響評價」指標"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00418', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '國民健康署網站有「健康學習資源」，連結中有文宣手冊及影音連結提供各樣的健康及衛教知 識，內容涵蓋各個人生階段（青少年、銀髮族）可能面對的健康議題。以渥太華憲章（1986 年）的行動綱領來看，這是屬於下列那一項？', '["訂定健康的公共政策", "創造有利健康的環境", "強化社區行動", "發展個人技巧"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00419', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', 'Sallis與Owen（2002年）認為應用生態模式設計健康介入方案時，應注意幾個原則，下列何 者錯誤？', '["需考量健康行為受到多層級因素的影響", "需依健康行為特性選擇適用的生態模式", "多層級介入需要跨部門或跨族群合作", "生態模式之各層級內的考量因素／變項間互為獨立"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00420', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某校老師發現近來性騷擾事件頻傳，於是以校園社區共同防護網為主題，邀請老師、附近里 長及家長參加，透過會議使學校、家長及社區代表了解性騷擾意義及防護通報等規定及交換 意見。該老師運用的是WHO在GlobalSchoolHealthInitiative中的那一個策略？', '["強化學校執行健康計畫的能力", "運用研究改善學校健康促進計畫", "將健康促進計畫提升為國家層級的政策", "建立健康促進學校的網絡和聯盟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00421', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某健康促進專家在規劃菸害防制計畫時，將影響吸菸行為的因素歸納為對菸害的知識、對戒 菸的態度及對肺癌的自覺罹患性。這樣的歸納可能會有下列何種情況產生？', '["過度推論造成原子謬誤", "僅著重個人層次的因素造成受害者責備", "將肺癌視為慢性病造成疾病轉型", "推動戒菸但無法降低吸菸盛行率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00422', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某健康中心欲進行以預防失智症為題之健康促進計畫，為了解社區居民對失智症的認知，因 此進行問卷調查以收集第一手資料。此計畫可能正處於下列那個階段？', '["發展介入", "執行介入策略", "文獻探討", "需求評估"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00423', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '因應人口快速老化的全球化趨勢，世界衛生組織（WHO）在2007年發布「高齡友善城市指 南」，有關高齡友善城市健康促進介入方案的規劃，下列敘述何者錯誤？', '["某縣市政府以發展「全齡藝文」為目標，將過去只能在展演廳觀賞的音樂藝文活動推廣至 社區日常生活，透過藝術下鄉在家門口開演，傳唱當地老一輩故事，便於長者在親友陪伴 下參加，此為高齡友善城市八大面向介入方案規劃之「親老」", "「高齡友善城市」目標乃創造有利於高齡者活動條件的場域，健康促進介入方案應以減少 場域各項障礙，增進高齡者參與為規劃重點", "「高齡友善城市指南」強調「健康」是基本人權，健康促進介入方案規劃推動「以環境安 全為最高設計原則」的高齡友善城市，落實healthinallpolicies，共創全齡共享、世代宜居 的永續城市", "某縣市政府結合企業及大學實現社會責任力量，推動幸福巴士上路，由企業捐贈小車及當 地民眾私家車權，作為「公車」掛上綠牌，填補山區交通缺口，嘉惠行動不便長者出入， 此為高齡友善城市八大面向介入方案規劃之「暢行」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00424', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '行政院發布自112年3月22日起施行菸害防制新法，以維護國人健康。這個方式屬於渥太華 憲章五大行動綱領的何者？', '["創造支持性環境", "強化社區行動", "建立健康的公共政策", "調整健康服務方向"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00425', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '隨著人口高齡化，許多縣市政府及民間機構紛紛推出銀髮就業平台媒合服務或是高齡就業服 務，這樣的趨勢符合衛生福利部推動高齡友善城市的那個面向？', '["安居", "親老", "敬老", "不老"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00426', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列對健康促進與社區營造之關鍵－夥伴關係建立的敘述，何者錯誤？', '["組織與組織間的財務支持，是有利於夥伴關係的因素", "社區組織之在地聲音（localvoiceinaction），設定健康議題的代表性，皆有利於夥伴關係之 建立", "批判與挑戰當前健康政策之執行，有利於組織與組織間之夥伴關係建立", "健康促進政策與社區夥伴關係，考慮因素包含當前健康議題、全球化、結盟合作、永續經 營等"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
